import{c as a,Q as n,j as t,m as p}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"安全监控与应急响应:IDS / SIEM / 取证 / 事件复盘","description":"","frontmatter":{},"headers":[],"relativePath":"securityLearning/29-安全监控与应急响应.md","filePath":"securityLearning/29-安全监控与应急响应.md","lastUpdated":1778496697000}'),i={name:"securityLearning/29-安全监控与应急响应.md"};function e(l,s,o,r,d,h){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="安全监控与应急响应-ids-siem-取证-事件复盘" tabindex="-1">安全监控与应急响应:IDS / SIEM / 取证 / 事件复盘 <a class="header-anchor" href="#安全监控与应急响应-ids-siem-取证-事件复盘" aria-label="Permalink to &quot;安全监控与应急响应:IDS / SIEM / 取证 / 事件复盘&quot;">​</a></h1><p>前 28 篇都在讲「<strong>怎么不被打</strong>」——防注入、防溢出、防错配、防投毒。但工业界一条很冷的常识是:<strong>只要你够大、暴露面够广,被打中是迟早的事</strong>——Google、Microsoft、Cloudflare 这种安全投入开到天上的公司每年也都被打,只是它们<strong>几小时内发现、几小时内处置</strong>,而被新闻头版的那些公司是<strong>几个月才发现自己被打了</strong>。这两种结局的差别不在「防」,在「<strong>发现 + 处置的速度</strong>」——这就是这一篇的主题。前面所有篇章都是「事前防御」,这一篇是「<strong>事中检测 + 事后响应</strong>」,合起来才是完整的安全闭环。</p><blockquote><p>一句话先记住:<strong>MTTD(平均发现时间)+ MTTR(平均响应时间)是衡量一个安全团队水平的硬指标</strong>——Mandiant 2024 年报告全球 dwell time 中位数 <strong>10 天</strong>,亚太区 <strong>9 天</strong>,而 ransomware 类只要 <strong>5 天</strong>;一流团队能压到 <strong>小时级</strong>,差团队是 <strong>月级</strong>。差别不是「工具好不好」,是「<strong>告警有没有人看、看了有没有人处置、处置完有没有人复盘</strong>」——三个独立的工程能力,缺一个都白搭。<strong>没人值班的告警 = 没有告警;没复盘的事件 = 等着第二次被同样手法打</strong>。</p></blockquote><hr><h2 id="一、为什么-被打了之后多久能发现-才是核心指标" tabindex="-1">一、为什么&quot;被打了之后多久能发现&quot;才是核心指标 <a class="header-anchor" href="#一、为什么-被打了之后多久能发现-才是核心指标" aria-label="Permalink to &quot;一、为什么&quot;被打了之后多久能发现&quot;才是核心指标&quot;">​</a></h2><h3 id="_1-1-dwell-time-攻击者在你网里待了多久" tabindex="-1">1.1 dwell time:攻击者在你网里待了多久 <a class="header-anchor" href="#_1-1-dwell-time-攻击者在你网里待了多久" aria-label="Permalink to &quot;1.1 dwell time:攻击者在你网里待了多久&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>攻击链:</span></span>
<span class="line"><span>  Day 0    钓鱼邮件 / 漏洞利用 / 凭据泄漏 落地</span></span>
<span class="line"><span>  Day 0+   植入 webshell / RAT,建立 C2 回连</span></span>
<span class="line"><span>  Day 1-7  横向移动 / 提权 / 摸地形</span></span>
<span class="line"><span>  Day 7+   收集数据 / 部署勒索 / 准备出货</span></span>
<span class="line"><span>  Day N    爆发(勒索弹窗 / 数据出现在暗网)</span></span>
<span class="line"><span>        ─────────────</span></span>
<span class="line"><span>        dwell time = Day 0 → 你发现的那一天</span></span></code></pre></div><p><strong>dwell time 越长损失越大</strong>,不是线性曲线——<strong>多 3 天可能从单台 webshell 升级到整域沦陷</strong>。Equifax 2017 那次 dwell time 是 76 天,1.4 亿条记录被拖走。SolarWinds 2020 那次,攻击者蹲了 9 个月才被发现。</p><h3 id="_1-2-三个指标-mttd-mttr-mttc" tabindex="-1">1.2 三个指标:MTTD / MTTR / MTTC <a class="header-anchor" href="#_1-2-三个指标-mttd-mttr-mttc" aria-label="Permalink to &quot;1.2 三个指标:MTTD / MTTR / MTTC&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>全称</th><th>含义</th></tr></thead><tbody><tr><td>MTTD</td><td>Mean Time To Detect</td><td>入侵发生 → 检测到</td></tr><tr><td>MTTR</td><td>Mean Time To Respond</td><td>检测到 → 开始处置</td></tr><tr><td>MTTC</td><td>Mean Time To Contain</td><td>检测到 → 完全控制</td></tr></tbody></table><p><strong>业内基准</strong>:顶级团队 MTTD &lt; 1h、MTTR &lt; 15min;中等公司 MTTD 一天 / MTTR 几小时;没有 SOC 的公司经常是「<strong>甲方或媒体告诉你被打了</strong>」,MTTD 数周到数月。</p><h3 id="_1-3-为什么-防-检测-必须双修" tabindex="-1">1.3 为什么&quot;防 + 检测&quot;必须双修 <a class="header-anchor" href="#_1-3-为什么-防-检测-必须双修" aria-label="Permalink to &quot;1.3 为什么&quot;防 + 检测&quot;必须双修&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>纯防御的错觉:</span></span>
<span class="line"><span>  装 WAF / EDR / 防火墙 → &quot;我安全了&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>真相:</span></span>
<span class="line"><span>  WAF 绕过技术每年都有新的</span></span>
<span class="line"><span>  EDR 在内核驱动层,可被 BYOVD 攻击禁用</span></span>
<span class="line"><span>  0day 永远存在</span></span>
<span class="line"><span>  钓鱼 / 内鬼 / 第三方供应链 绕开你所有外部防御</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  → 防御只能拦&quot;已知 + 笨&quot;的攻击</span></span>
<span class="line"><span>  → 检测才能发现&quot;未知 + 聪明&quot;的攻击</span></span></code></pre></div><p><strong>纵深防御的下半段是&quot;假定已经被打&quot;</strong>——这就是为什么大公司都有 SOC 和 Threat Hunting 团队,他们的工作不是&quot;防&quot;,是「<strong>假设网里已经有攻击者了,把他找出来</strong>」。</p><hr><h2 id="二、ids-ips-在流量上发现攻击" tabindex="-1">二、IDS / IPS:在流量上发现攻击 <a class="header-anchor" href="#二、ids-ips-在流量上发现攻击" aria-label="Permalink to &quot;二、IDS / IPS:在流量上发现攻击&quot;">​</a></h2><h3 id="_2-1-ids-vs-ips-旁路-vs-串行" tabindex="-1">2.1 IDS vs IPS:旁路 vs 串行 <a class="header-anchor" href="#_2-1-ids-vs-ips-旁路-vs-串行" aria-label="Permalink to &quot;2.1 IDS vs IPS:旁路 vs 串行&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IDS — 旁路镜像:流量 → 交换机 SPAN 口 → IDS → 只告警不阻断</span></span>
<span class="line"><span>       优点:不影响业务  缺点:看到了也来不及拦</span></span>
<span class="line"><span>IPS — 串行阻断:流量 → IPS → 转发/丢弃 → 后端</span></span>
<span class="line"><span>       优点:能拦      缺点:误报会断业务</span></span></code></pre></div><p><strong>业内常态</strong>:核心链路 IPS,办公网 / DMZ 上 IDS。「能拦就拦,不能拦至少告警」。</p><h3 id="_2-2-签名规则-vs-异常检测" tabindex="-1">2.2 签名规则 vs 异常检测 <a class="header-anchor" href="#_2-2-签名规则-vs-异常检测" aria-label="Permalink to &quot;2.2 签名规则 vs 异常检测&quot;">​</a></h3><p><strong>签名规则</strong>:特征已知攻击。比如 SQLi 看 URI 里 <code>union select</code>,Log4Shell 看 header 里 <code>\${jndi:ldap://</code>。<strong>误报低可解释,但只能找已知攻击</strong>——0day 看不见。</p><p><strong>异常检测</strong>:先建基线(&quot;这台机器平时只和 10 个 IP 通信&quot;),偏离即告警。<strong>能发现未知,但误报高、基线漂移</strong>(业务变化也告警)。</p><blockquote><p><strong>现代检测是&quot;签名 + 异常 + 机器学习&quot;组合</strong>——纯签名跟不上 0day,纯异常误报到没人看。</p></blockquote><h3 id="_2-3-snort-suricata-zeek" tabindex="-1">2.3 Snort / Suricata / Zeek <a class="header-anchor" href="#_2-3-snort-suricata-zeek" aria-label="Permalink to &quot;2.3 Snort / Suricata / Zeek&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>定位</th><th>长处</th></tr></thead><tbody><tr><td><strong>Snort</strong></td><td>老牌 IDS / IPS,1998 年开始</td><td>规则生态最完整(Talos / ET)</td></tr><tr><td><strong>Suricata</strong></td><td>现代 IDS / IPS,多线程</td><td>性能强,兼容 Snort 规则</td></tr><tr><td><strong>Zeek</strong>(原 Bro)</td><td>网络行为分析框架</td><td><strong>不是规则,是脚本</strong> —— 记录所有连接元数据</td></tr></tbody></table><p>Zeek 的不同——它<strong>不告警,记录一切</strong>:<code>conn.log</code> / <code>http.log</code> / <code>dns.log</code> / <code>ssl.log</code> / <code>files.log</code>。这些日志后面喂给 SIEM 做<strong>事后调查</strong>——你不知道明天怎么被打,但 Zeek 把今天的一切录下来,等你回去翻。</p><h3 id="_2-4-ids-越来越难做" tabindex="-1">2.4 IDS 越来越难做 <a class="header-anchor" href="#_2-4-ids-越来越难做" aria-label="Permalink to &quot;2.4 IDS 越来越难做&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TLS 普及     → IDS 看不见 HTTP body(只能看 SNI / cert)</span></span>
<span class="line"><span>HTTP/3 QUIC → 跑 UDP 上,很多 IDS 还不支持</span></span>
<span class="line"><span>家用 VPN     → 员工流量被代理走</span></span>
<span class="line"><span>云原生       → 东西向流量在 VPC 里,边界 IDS 看不到</span></span></code></pre></div><p><strong>这就是为什么主机层 EDR 越来越重要</strong>——网络看不见的,主机能看见。</p><hr><h2 id="三、主机层-edr-在终端上发现攻击" tabindex="-1">三、主机层 EDR:在终端上发现攻击 <a class="header-anchor" href="#三、主机层-edr-在终端上发现攻击" aria-label="Permalink to &quot;三、主机层 EDR:在终端上发现攻击&quot;">​</a></h2><h3 id="_3-1-edr-到底看什么" tabindex="-1">3.1 EDR 到底看什么 <a class="header-anchor" href="#_3-1-edr-到底看什么" aria-label="Permalink to &quot;3.1 EDR 到底看什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程创建链:   谁 fork 了谁,执行了什么命令</span></span>
<span class="line"><span>文件操作:    哪个进程写了哪个 .exe / .dll / .sh</span></span>
<span class="line"><span>注册表 / 配置: 持久化痕迹</span></span>
<span class="line"><span>网络连接:    哪个进程连了哪个 IP / 域名</span></span>
<span class="line"><span>脚本解释器:   PowerShell / cmd / bash 全量命令行</span></span>
<span class="line"><span>DLL 注入:    进程内存里出现不属于它的模块</span></span>
<span class="line"><span>凭据访问:    谁读了 LSASS / /etc/shadow</span></span></code></pre></div><p><strong>经典攻击链</strong>(MITRE ATT&amp;CK 都有分类):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Office Word → cmd.exe → powershell -enc &lt;base64&gt; → 下载 EXE → 落地</span></span></code></pre></div><p>单看每一步都&quot;正常&quot;,<strong>串起来就是钓鱼链</strong>。EDR 的关键能力就是<strong>把链拼出来</strong>。</p><h3 id="_3-2-工具谱系" tabindex="-1">3.2 工具谱系 <a class="header-anchor" href="#_3-2-工具谱系" aria-label="Permalink to &quot;3.2 工具谱系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>定位</th><th>适合</th></tr></thead><tbody><tr><td><strong>Sysmon</strong>(Windows)</td><td>微软官方,免费,只采集</td><td>小团队 / 自建检测底座</td></tr><tr><td><strong>osquery</strong></td><td>Facebook 开源,SQL 查主机状态</td><td>跨平台</td></tr><tr><td><strong>Wazuh</strong></td><td>开源 EDR + SIEM 一体</td><td>中小企业</td></tr><tr><td><strong>CrowdStrike Falcon / SentinelOne / Defender for Endpoint</strong></td><td>商业 EDR</td><td>大企业,贵但好用</td></tr><tr><td><strong>Velociraptor</strong></td><td>开源 DFIR 平台</td><td>事件响应时大规模采集</td></tr></tbody></table><h3 id="_3-3-osquery-把主机变成数据库" tabindex="-1">3.3 osquery 把主机变成数据库 <a class="header-anchor" href="#_3-3-osquery-把主机变成数据库" aria-label="Permalink to &quot;3.3 osquery 把主机变成数据库&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查所有监听端口</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pid, port, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">address</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> listening_ports;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查最近创建的 setuid 文件</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, mtime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> file</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;/usr/bin/%&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;4%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查所有 cron 任务</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> crontab;</span></span></code></pre></div><p><strong>全公司主机当一张大表查</strong>——事件响应时极其值钱:「<strong>有没有别的机器也被同样手法打了</strong>」从「挨个登 100 台」变成「一行 SQL」。</p><hr><h2 id="四、siem-把所有日志汇成一张图" tabindex="-1">四、SIEM:把所有日志汇成一张图 <a class="header-anchor" href="#四、siem-把所有日志汇成一张图" aria-label="Permalink to &quot;四、SIEM:把所有日志汇成一张图&quot;">​</a></h2><h3 id="_4-1-siem-干什么" tabindex="-1">4.1 SIEM 干什么 <a class="header-anchor" href="#_4-1-siem-干什么" aria-label="Permalink to &quot;4.1 SIEM 干什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 采集:syslog / EDR / IDS / 应用 / 云 全汇总</span></span>
<span class="line"><span>2. 关联:跨源 join(IDS 报 SQLi + Nginx 看到 500 响应 → 同一事件)</span></span>
<span class="line"><span>3. 检测:跑规则触发告警</span></span>
<span class="line"><span>4. 调查:给分析师查询界面,事件回溯</span></span></code></pre></div><h3 id="_4-2-工具谱系" tabindex="-1">4.2 工具谱系 <a class="header-anchor" href="#_4-2-工具谱系" aria-label="Permalink to &quot;4.2 工具谱系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>备注</th></tr></thead><tbody><tr><td><strong>Splunk</strong></td><td>商业 SIEM 之王,<strong>贵到劝退</strong>(按摄入量计费,GB / 天)</td></tr><tr><td><strong>Elastic SIEM</strong></td><td>ELK 一脉,中等规模主流</td></tr><tr><td><strong>OpenSearch</strong></td><td>AWS fork 的 Elastic,完全开源</td></tr><tr><td><strong>Wazuh</strong></td><td>开源 SIEM + EDR,小团队首选</td></tr><tr><td><strong>Sumo / Datadog / Chronicle</strong></td><td>SaaS SIEM,不想自己运维就用</td></tr></tbody></table><p>Splunk 为什么贵:大公司每天日志 TB 级,<strong>一年许可费可能上百万美元</strong>——常见的对策是「<strong>热数据 Splunk,冷数据下沉到 S3 + Athena</strong>」。</p><h3 id="_4-3-一条告警的流转" tabindex="-1">4.3 一条告警的流转 <a class="header-anchor" href="#_4-3-一条告警的流转" aria-label="Permalink to &quot;4.3 一条告警的流转&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nginx 日志 → Filebeat → Logstash(解析)→ Elasticsearch(存储)</span></span>
<span class="line"><span>                                              ↓</span></span>
<span class="line"><span>                                        SIEM 规则引擎</span></span>
<span class="line"><span>                                              ↓</span></span>
<span class="line"><span>                                  告警(邮件 / Slack / PagerDuty)</span></span>
<span class="line"><span>                                              ↓</span></span>
<span class="line"><span>                                  值班同事接收 → 分诊</span></span></code></pre></div><p><strong>关键瓶颈不在工具,在&quot;值班&quot;</strong>——半夜 3 点没人看 = 没告警;告警没分级 = P3 淹了 P1;告警没上下文 = 一行 IP+URL 不知道怎么处置。</p><h3 id="_4-4-日志收集层" tabindex="-1">4.4 日志收集层 <a class="header-anchor" href="#_4-4-日志收集层" aria-label="Permalink to &quot;4.4 日志收集层&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>角色</th></tr></thead><tbody><tr><td><strong>syslog / rsyslog</strong></td><td>老牌 Linux 日志协议</td></tr><tr><td><strong>journald</strong></td><td>systemd 日志,结构化但默认本地</td></tr><tr><td><strong>Filebeat / Logstash</strong>(Elastic 系)</td><td>文件 → 解析 → 转发</td></tr><tr><td><strong>Fluentd / Fluent Bit</strong>(CNCF)</td><td>云原生 K8s 主流</td></tr><tr><td><strong>Vector</strong>(Rust 写)</td><td>高性能新秀,日志 + 指标 + Trace 统一</td></tr></tbody></table><p><strong>常见架构</strong>:<code>应用 stdout → 容器日志驱动 → Fluent Bit (daemonset) → Kafka(缓冲) → Logstash/Vector(解析) → ES/S3 → SIEM</code>。<strong>为什么必须有 Kafka</strong>:出事故时日志 10× 暴涨会把下游 ES 打挂,Kafka 做缓冲。</p><hr><h2 id="五、sigma-统一的检测规则格式" tabindex="-1">五、Sigma:统一的检测规则格式 <a class="header-anchor" href="#五、sigma-统一的检测规则格式" aria-label="Permalink to &quot;五、Sigma:统一的检测规则格式&quot;">​</a></h2><p><strong>痛点</strong>:每家 SIEM 规则语法都不一样——Splunk SPL / Elastic KQL / Sentinel KQL / Splunk ES,<strong>换工具 = 规则全重写;社区分享规则没法复用</strong>。</p><p><strong>Sigma 用 YAML 写&quot;通用规则&quot;</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Suspicious PowerShell Encoded Command</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">logsource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">product</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">windows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">category</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">process_creation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">detection</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    selection</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        Image|endswith</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;\\powershell.exe&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        CommandLine|contains</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;-enc&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    condition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">selection</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">high</span></span></code></pre></div><p>配合 <code>sigmac</code> 转换器,<strong>一份 YAML 编译成各家 SIEM 的方言</strong>。SigmaHQ 仓库几千条公开规则,做 Threat Hunting 时常去捞。</p><hr><h2 id="六、soar-把-人重复做的-自动化" tabindex="-1">六、SOAR:把&quot;人重复做的&quot;自动化 <a class="header-anchor" href="#六、soar-把-人重复做的-自动化" aria-label="Permalink to &quot;六、SOAR:把&quot;人重复做的&quot;自动化&quot;">​</a></h2><p><strong>为什么纯靠人不行</strong>:中型公司一天 1000-10000 条告警,2-5 个分析师,一条 5 分钟——<strong>一个人一天极限 ~80 条,90% 告警没人看</strong>。真攻击就藏在这堆里。</p><p><strong>SOAR 的核心是剧本(playbook)</strong> ——把&quot;人做的判断&quot;编成自动化:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      告警触发</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>   [取 IP 威胁情报]──[查 VT / AbuseIPDB]</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>   IP 是 known bad?</span></span>
<span class="line"><span>   │           │</span></span>
<span class="line"><span>  YES         NO</span></span>
<span class="line"><span>   │           │</span></span>
<span class="line"><span>[自动隔离]   [发给分析师人工判断]</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>[发工单 + 通知]</span></span></code></pre></div><p><strong>平台</strong>:Splunk SOAR(原 Phantom)、Cortex XSOAR、Tines、Shuffle(开源)。</p><p><strong>适合自动化</strong>:机械重复(查 IP 信誉、拉 VT 报告、kick session)+ 确定性高的响应(封 IP、隔离主机)。</p><p><strong>不适合自动化</strong>:涉及业务判断(&quot;这个 IP 是真攻击还是合作伙伴扫描&quot;)+ 高破坏性(误封 CEO 邮箱)+ 复杂取证。</p><blockquote><p>经验:<strong>SOAR 解决 80% 重复活,剩下 20% 高价值判断留给人</strong>。一上来想全自动是死路。</p></blockquote><hr><h2 id="七、应急响应六步法-picerl" tabindex="-1">七、应急响应六步法:PICERL <a class="header-anchor" href="#七、应急响应六步法-picerl" aria-label="Permalink to &quot;七、应急响应六步法:PICERL&quot;">​</a></h2><p>NIST SP 800-61 经典模型:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P  Preparation     事前准备</span></span>
<span class="line"><span>I  Identification  发现 / 确认</span></span>
<span class="line"><span>C  Containment     遏制(止血)</span></span>
<span class="line"><span>E  Eradication     根除</span></span>
<span class="line"><span>R  Recovery        恢复</span></span>
<span class="line"><span>L  Lessons Learned 复盘</span></span></code></pre></div><h3 id="_7-1-preparation-平时养兵-最被忽视、回报最高" tabindex="-1">7.1 Preparation:平时养兵(最被忽视、回报最高) <a class="header-anchor" href="#_7-1-preparation-平时养兵-最被忽视、回报最高" aria-label="Permalink to &quot;7.1 Preparation:平时养兵(最被忽视、回报最高)&quot;">​</a></h3><p>IR 团队职责 + 轮值表 / 联系人清单(法务 / 公关 / 高管 / 监管)/ 取证工具箱 / 沙箱就位 / out-of-band 沟通信道(出事时主信道可能失效)/ <strong>桌面演习(tabletop)半年一次</strong>。</p><h3 id="_7-2-identification-确认是不是真事件" tabindex="-1">7.2 Identification:确认是不是真事件 <a class="header-anchor" href="#_7-2-identification-确认是不是真事件" aria-label="Permalink to &quot;7.2 Identification:确认是不是真事件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>信号来源:SIEM 告警 / EDR 触发 / 用户报告 / 外部通报 / 监管约谈(最糟糕)</span></span>
<span class="line"><span>要决定:  严重程度(P0-P4)/ 影响范围 / 是否升级到全公司 IR</span></span></code></pre></div><p><strong>别立刻动手</strong>——新手一看告警就 <code>kill -9</code> + 拔网线,<strong>把所有取证痕迹毁掉</strong>,后面根因分析做不下去。<strong>先评估,再动手</strong>。</p><h3 id="_7-3-containment-止血" tabindex="-1">7.3 Containment:止血 <a class="header-anchor" href="#_7-3-containment-止血" aria-label="Permalink to &quot;7.3 Containment:止血&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>短期(分钟级):隔离主机 / 禁用账户 / 撤销 token / 临时下线服务</span></span>
<span class="line"><span>长期(小时-天):部署临时 WAF 规则 / 改密码 / 轮换密钥 / 网段隔离</span></span></code></pre></div><p><strong>两难</strong>:隔离越激进业务影响越大;越保守攻击者越可能扩大战果。<strong>没有银弹,现场判断</strong>。</p><h3 id="_7-4-eradication-挖干净" tabindex="-1">7.4 Eradication:挖干净 <a class="header-anchor" href="#_7-4-eradication-挖干净" aria-label="Permalink to &quot;7.4 Eradication:挖干净&quot;">​</a></h3><p>找入口 → 找所有 IOC(Indicator of Compromise:恶意 IP / 域名 / 文件 hash / 注册表项)→ 全网搜 IOC → <strong>重装系统(rebuild,不是 clean)</strong>。</p><blockquote><p>「<strong>清掉 webshell 就行了</strong>」是最常见错误——webshell 是表象,<strong>真后门可能是计划任务 / systemd 服务 / SSH key / 篡改过的 sudo / BIOS implant</strong>。<strong>专业 IR 默认 rebuild</strong>。</p></blockquote><h3 id="_7-5-recovery-业务回正" tabindex="-1">7.5 Recovery:业务回正 <a class="header-anchor" href="#_7-5-recovery-业务回正" aria-label="Permalink to &quot;7.5 Recovery:业务回正&quot;">​</a></h3><p>从干净备份恢复 → 验证(扫 IOC 确认干净)→ 灰度上线 → 全量 → <strong>被打过的地方 7×24 重点盯一段时间</strong>。</p><h3 id="_7-6-lessons-learned-复盘" tabindex="-1">7.6 Lessons Learned:复盘 <a class="header-anchor" href="#_7-6-lessons-learned-复盘" aria-label="Permalink to &quot;7.6 Lessons Learned:复盘&quot;">​</a></h3><p>事件 RCA 文档要回答:时间线 / 根因 / 哪里检测晚了 / 哪里响应慢了 / 下次怎么早一步发现 / action items(谁负责什么时候做完)。</p><p><strong>复盘原则:对事不对人(blameless postmortem)</strong> ——找系统漏洞不找责任人,不然下次没人敢报告事件。</p><blockquote><p><strong>没复盘的事件 = 等着第二次被同样手法打</strong>。</p></blockquote><hr><h2 id="八、数字取证-把现场冻住-慢慢看" tabindex="-1">八、数字取证:把现场冻住,慢慢看 <a class="header-anchor" href="#八、数字取证-把现场冻住-慢慢看" aria-label="Permalink to &quot;八、数字取证:把现场冻住,慢慢看&quot;">​</a></h2><h3 id="_8-1-取证铁律-order-of-volatility" tabindex="-1">8.1 取证铁律:order of volatility <a class="header-anchor" href="#_8-1-取证铁律-order-of-volatility" aria-label="Permalink to &quot;8.1 取证铁律:order of volatility&quot;">​</a></h3><p><strong>易失性高的先取</strong>——RAM 一断电就没,磁盘可以慢慢取:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 寄存器 / cache         (毫秒级丢失,不实际取)</span></span>
<span class="line"><span>2. 内存(RAM)             ← 重中之重,LiME / WinPmem</span></span>
<span class="line"><span>3. 网络状态(连接 / 路由) ← ss / netstat</span></span>
<span class="line"><span>4. 进程 / 内存映射         ← /proc 快照</span></span>
<span class="line"><span>5. 临时文件 / swap         ← /tmp /var/tmp</span></span>
<span class="line"><span>6. 磁盘                    ← dd / ddrescue / FTK Imager</span></span>
<span class="line"><span>7. 远程日志                ← syslog 服务器</span></span></code></pre></div><h3 id="_8-2-磁盘镜像-校验" tabindex="-1">8.2 磁盘镜像 + 校验 <a class="header-anchor" href="#_8-2-磁盘镜像-校验" aria-label="Permalink to &quot;8.2 磁盘镜像 + 校验&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 概念性命令,实际配合 write-blocker + 取证工具</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sda</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> before.hash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/sda</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=disk.img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=4M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=sync,noerror</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disk.img</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> after.hash</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># before / after 必须一致 —— 证明&quot;我没改原盘&quot;</span></span></code></pre></div><p>取证证据要在法庭 / 监管面前可信,<strong>必须证明从取证那一刻到分析,文件没被改过</strong>。</p><h3 id="_8-3-内存取证-看到磁盘看不到的" tabindex="-1">8.3 内存取证:看到磁盘看不到的 <a class="header-anchor" href="#_8-3-内存取证-看到磁盘看不到的" aria-label="Permalink to &quot;8.3 内存取证:看到磁盘看不到的&quot;">​</a></h3><p>磁盘上没痕迹的攻击:<strong>无文件攻击</strong>(fileless,只在 RAM 跑 PowerShell)/ 进程注入 / rootkit hook。<strong>必须看 RAM</strong>。</p><p>Volatility 经典命令(示意):<code>pslist</code>(进程)/ <code>netscan</code>(连接)/ <code>malfind</code>(注入代码)/ <code>dumpfiles</code>(提取内存里的文件)。</p><h3 id="_8-4-时间线分析" tabindex="-1">8.4 时间线分析 <a class="header-anchor" href="#_8-4-时间线分析" aria-label="Permalink to &quot;8.4 时间线分析&quot;">​</a></h3><p>所有事件按时间排序,<strong>故事一目了然</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>02:13:07  /tmp/.cache/x  文件创建      (来自 sshd worker)</span></span>
<span class="line"><span>02:13:08  端口 4444  新增 LISTEN       (PID 12453)</span></span>
<span class="line"><span>02:13:09  /etc/cron.d/clean  修改      (root 写)</span></span>
<span class="line"><span>02:14:32  外联 185.x.x.x:443           (PID 12453)</span></span>
<span class="line"><span>02:15:10  /etc/passwd  读取            (PID 12453)</span></span>
<span class="line"><span>02:17:42  /root/.ssh/authorized_keys  追加</span></span></code></pre></div><p>故事清晰:<strong>02:13 之前一切正常 → sshd 触发 → 释放后门 → 改 cron 持久化 → 外联 C2 → 读密码文件 → 加 SSH 公钥</strong>。入口很可能是 SSH 弱口令或漏洞。这就是 IR 报告的核心交付物:<strong>时间线 + 根因 + IOC 列表</strong>。</p><h3 id="_8-5-攻击者反取证-防御方要预防" tabindex="-1">8.5 攻击者反取证(防御方要预防) <a class="header-anchor" href="#_8-5-攻击者反取证-防御方要预防" aria-label="Permalink to &quot;8.5 攻击者反取证(防御方要预防)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>删日志(rm /var/log/* / journalctl --vacuum)</span></span>
<span class="line"><span>  → 防御:日志实时外送到独立 SIEM 服务器</span></span>
<span class="line"><span>改时间戳(touch -t)</span></span>
<span class="line"><span>  → 防御:对比 atime / mtime / ctime + inode change time</span></span>
<span class="line"><span>内存运行不落盘</span></span>
<span class="line"><span>  → 防御:EDR 监控进程内存 + 网络外联</span></span>
<span class="line"><span>清 .bash_history / wevtutil cl</span></span>
<span class="line"><span>  → 防御:命令审计独立采集(auditd / Sysmon)</span></span>
<span class="line"><span>LOLBin(用系统自带 certutil / bitsadmin 下载)</span></span>
<span class="line"><span>  → 防御:基线 + 告警(&quot;certutil 怎么会从这台机器发起?&quot;)</span></span>
<span class="line"><span>BYOVD(Bring Your Own Vulnerable Driver)关 EDR</span></span>
<span class="line"><span>  → 防御:驱动签名白名单 / WDAC / 监控驱动加载</span></span></code></pre></div><p><strong>核心</strong>:<strong>取证数据不能存在被攻击的机器上,必须实时外送</strong>。等出事再去原机器找日志,大概率已经被擦干净了。</p><hr><h2 id="九、蓝队日常-告警分诊-误报治理-检测调优" tabindex="-1">九、蓝队日常:告警分诊 / 误报治理 / 检测调优 <a class="header-anchor" href="#九、蓝队日常-告警分诊-误报治理-检测调优" aria-label="Permalink to &quot;九、蓝队日常:告警分诊 / 误报治理 / 检测调优&quot;">​</a></h2><p><strong>Tier 分层</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tier 1   7×24 值班,快速分诊 + 简单处置(80% 告警在这层)</span></span>
<span class="line"><span>Tier 2   复杂事件调查 + 取证(10%)</span></span>
<span class="line"><span>Tier 3   Threat Hunting + 检测规则开发(5%)</span></span>
<span class="line"><span>IR Team  重大事件统筹(&lt;5%,但每次都是大事)</span></span></code></pre></div><p><strong>误报治理</strong>:<strong>误报杀死告警系统</strong>——一旦 90% 是误报,人就开始无视所有告警,<strong>真攻击来了也被淹</strong>。每条规则定期看 precision(真阳率),&lt; 80% 就调规则 / 加白名单 / 改阈值;维护资产清单给告警上下文(&quot;这台是 DB,不该有 outbound 80&quot;);用威胁情报富化(IP / 域名 / hash 自动查 VT);多条信号关联。</p><p><strong>检测调优</strong>:新威胁 → 写规则 → 上线观察一周 → 误报多就调阈值 / 加白名单 → 漏报就多源关联 → 稳定后入主规则集。<strong>MITRE ATT&amp;CK 覆盖率</strong>是检测团队的核心 KPI——~600 个 technique,<strong>能检测多少个就是检测能力上限</strong>。</p><hr><h2 id="十、真实事件复盘-一次从告警到根因的时间线" tabindex="-1">十、真实事件复盘:一次从告警到根因的时间线 <a class="header-anchor" href="#十、真实事件复盘-一次从告警到根因的时间线" aria-label="Permalink to &quot;十、真实事件复盘:一次从告警到根因的时间线&quot;">​</a></h2><p><strong>场景</strong>:某中型公司,白天突然 SIEM 触发告警。<strong>所有 IP / 时间是虚构示意</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>14:02:11  SIEM 告警:internal 10.20.5.42 外联 185.x.x.x:443 (新 IP)</span></span>
<span class="line"><span>14:02:11  威胁情报匹配:185.x.x.x 是 known C2(Cobalt Strike teamserver)</span></span>
<span class="line"><span>14:02:13  告警进入 P1,自动 ping 值班</span></span>
<span class="line"><span>14:02:45  Tier 1 接手,EDR 看 10.20.5.42:</span></span>
<span class="line"><span>            └─ 异常进程 svchost.exe(假冒,实际路径 C:\\Users\\xxx\\AppData)</span></span>
<span class="line"><span>14:03:20  SOAR playbook 启动:</span></span>
<span class="line"><span>            ① EDR 隔离 10.20.5.42</span></span>
<span class="line"><span>            ② 防火墙 block 185.x.x.x 全公司</span></span>
<span class="line"><span>            ③ 关联查询近 24h 谁还连过这 IP → 找到第二台 10.20.7.13</span></span>
<span class="line"><span>14:05:00  Tier 2 介入,EDR 隔离第二台</span></span>
<span class="line"><span>14:10:00  开始取证:抓内存 + 磁盘镜像</span></span>
<span class="line"><span>14:30:00  Volatility 分析:Cobalt Strike beacon,定时 60s 回连</span></span>
<span class="line"><span>15:00:00  时间线反推:</span></span>
<span class="line"><span>            └─ 13:48 10.20.5.42 收到钓鱼邮件 + .docm 附件</span></span>
<span class="line"><span>            └─ 13:51 用户打开 docm → 触发宏 → 释放 beacon</span></span>
<span class="line"><span>            └─ 13:55 beacon 第一次回连(未告警,IP 还在白名单期内)</span></span>
<span class="line"><span>            └─ 14:02 beacon 切到新 C2 IP(新 IP 不在白名单,触发)</span></span>
<span class="line"><span>16:00:00  全网搜 IOC:钓鱼 sender + docm hash + C2 IP</span></span>
<span class="line"><span>            └─ 另外 3 个用户收到同一封邮件,2 个没点,1 个隔离机已处理</span></span>
<span class="line"><span>17:30:00  根除:邮件网关全删,EDR 推签名,被打 2 台 rebuild</span></span>
<span class="line"><span>当日       Recovery + 监控加强</span></span>
<span class="line"><span>T+1        全员钓鱼演练 + 安全提醒</span></span>
<span class="line"><span>T+3        Lessons Learned 会议:</span></span>
<span class="line"><span>            ① 邮件网关沙箱漏过 docm,加规则</span></span>
<span class="line"><span>            ② EDR 没在第一次回连(13:55)就告警,IP 还没在情报库</span></span>
<span class="line"><span>              → 加规则:任何新出口 IP 都要灰度告警</span></span>
<span class="line"><span>            ③ 用户安全意识 → 月度演练</span></span></code></pre></div><p><strong>关键复盘点</strong>:</p><ul><li><strong>MTTD = 14 min</strong>(13:48 入侵 → 14:02 告警)。不算快但可接受</li><li><strong>MTTR = 34 sec</strong>(14:02:11 告警 → 14:02:45 接手)。很快,值班有效</li><li><strong>MTTC = 18 min</strong>(14:02:11 告警 → 第二台隔离)。可以更快,SOAR 应自动连锁</li></ul><blockquote><p>这是一次「<strong>还行</strong>」的事件——损失可控,根因清晰。<strong>真正灾难性的事件是 MTTD 60 天起</strong>——那种就是 ransomware 弹窗了才知道完了。</p></blockquote><hr><h2 id="十一、小公司从零搭建监控的最小栈" tabindex="-1">十一、小公司从零搭建监控的最小栈 <a class="header-anchor" href="#十一、小公司从零搭建监控的最小栈" aria-label="Permalink to &quot;十一、小公司从零搭建监控的最小栈&quot;">​</a></h2><p>预算极有限的小团队怎么起步?<strong>全免费 / 开源,够用就行</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日志收集:   Fluent Bit (agent) → Kafka(可省)→ Elasticsearch / OpenSearch</span></span>
<span class="line"><span>SIEM:      Wazuh(开源,EDR + SIEM 一体)/ 或 Elastic SIEM 免费版</span></span>
<span class="line"><span>主机层:     Wazuh agent + Sysmon(Windows)+ auditd(Linux)</span></span>
<span class="line"><span>网络层:     Suricata(IDS,镜像核心交换机)+ Zeek(连接元数据)</span></span>
<span class="line"><span>威胁情报:   AbuseIPDB / VirusTotal 免费 API + MISP(自建,开源)</span></span>
<span class="line"><span>SOAR:      Shuffle(开源)/ Tines 免费版</span></span>
<span class="line"><span>告警通道:   PagerDuty 免费 / Opsgenie / Slack webhook</span></span>
<span class="line"><span>值班:       初期不用 7×24,但要&quot;工作时间内 &lt; 30 min 响应&quot; SLA</span></span>
<span class="line"><span>节奏:       每月一次桌面演习 + 检测规则梳理</span></span></code></pre></div><p><strong>总投入</strong>:1-2 人兼职 + 几台中等服务器,<strong>就能撑住 200 人公司的安全监控基本盘</strong>。</p><blockquote><p><strong>不要一上来就买 Splunk + CrowdStrike + Palo Alto</strong> ——预算全砸工具就没钱招人;<strong>没人值班的工具 = 没工具</strong>。<strong>先建团队,工具后补</strong>。</p></blockquote><hr><h2 id="十二、应急响应剧本-playbook-模板" tabindex="-1">十二、应急响应剧本(playbook)模板 <a class="header-anchor" href="#十二、应急响应剧本-playbook-模板" aria-label="Permalink to &quot;十二、应急响应剧本(playbook)模板&quot;">​</a></h2><p>下面这份是<strong>通用 IR 剧本骨架</strong>,落地时按具体威胁(钓鱼 / 勒索 / 数据泄漏 / 内鬼 / 0day)定制。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>─────────────────────────────────────────────</span></span>
<span class="line"><span>事件名:       [自动填]      事件编号:INC-[自动填]</span></span>
<span class="line"><span>触发时间:     [自动填]      严重程度:[P0/P1/P2/P3]</span></span>
<span class="line"><span>事件指挥官:   [必填]        当前状态:[检测中/处置中/已遏制/已根除/复盘中/关闭]</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【0】启动(15 分钟内完成)</span></span>
<span class="line"><span>□ 建立专用 war room(Slack / 电话桥)</span></span>
<span class="line"><span>□ 通知:CTO / SecLead / 法务(P0/P1 必须)</span></span>
<span class="line"><span>□ 指派 事件指挥官 / 取证负责人 / 沟通负责人</span></span>
<span class="line"><span>□ 开始时间线记录(谁在几点做了什么)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【1】Identification</span></span>
<span class="line"><span>□ 告警是否为 true positive</span></span>
<span class="line"><span>□ 影响范围(主机 / 用户 / 服务 / 数据)</span></span>
<span class="line"><span>□ 入侵手法初判(钓鱼 / 漏洞 / 凭据 / 内鬼 / 供应链)</span></span>
<span class="line"><span>□ 是否涉及 PII / 财务 / 客户数据(决定是否触发监管通报)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【2】Containment(目标 &lt; 1h)</span></span>
<span class="line"><span>□ 隔离受感染主机(EDR / 防火墙)</span></span>
<span class="line"><span>□ 禁用涉事账户 / 撤销 token</span></span>
<span class="line"><span>□ 屏蔽已知恶意 IP / 域名 / 邮件 sender</span></span>
<span class="line"><span>□ 临时下线 / 降级受影响服务</span></span>
<span class="line"><span>□ 决策点:激进隔离 vs 业务影响 —— 由指挥官拍板</span></span>
<span class="line"><span>□ 保留取证现场(不要直接关机,先抓内存)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【3】Investigation &amp; Eradication</span></span>
<span class="line"><span>□ 取证:内存 / 磁盘 / 日志快照</span></span>
<span class="line"><span>□ 时间线分析 → 找根因</span></span>
<span class="line"><span>□ 提取 IOC(IP / 域名 / hash / 用户 / 邮件主题)</span></span>
<span class="line"><span>□ 全网横向扫描 IOC,找出所有被波及主机</span></span>
<span class="line"><span>□ 邮件网关 / WAF / EDR 推送签名</span></span>
<span class="line"><span>□ 重装(rebuild)受感染主机,不要 clean</span></span>
<span class="line"><span>□ 轮换所有可能泄漏的凭据 / 密钥 / Token</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【4】Recovery</span></span>
<span class="line"><span>□ 从干净备份恢复数据</span></span>
<span class="line"><span>□ 验证恢复主机干净(IOC + EDR 全量)</span></span>
<span class="line"><span>□ 灰度 → 全量</span></span>
<span class="line"><span>□ 重点监控 7-14 天</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【5】Communication(贯穿全程)</span></span>
<span class="line"><span>□ 内部:每 30 min 状态同步(P1)/ 2h(P2)</span></span>
<span class="line"><span>□ 高管:重大节点必须通知</span></span>
<span class="line"><span>□ 法务 / 公关:涉及客户数据时必须介入</span></span>
<span class="line"><span>□ 客户:按法规要求时间窗内通知</span></span>
<span class="line"><span>□ 监管:按法规(GDPR 72h / 各地 CSL)</span></span>
<span class="line"><span>□ 警方:涉及犯罪 / 重大资产损失</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【6】Closure</span></span>
<span class="line"><span>□ 所有系统已恢复并验证</span></span>
<span class="line"><span>□ 所有 IOC 已封禁</span></span>
<span class="line"><span>□ 没有新的相关告警 72h</span></span>
<span class="line"><span>□ 事件报告(事实层)</span></span>
<span class="line"><span>□ 召开 Lessons Learned 会议(blameless)</span></span>
<span class="line"><span>□ 产出 action items(责任人 + DDL)</span></span>
<span class="line"><span>□ 跟踪 action items 至全部完成</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span></code></pre></div><p><strong>两条软原则</strong>:</p><ol><li><strong>指挥官说了算</strong>——技术专家可以建议,但拍板权统一。否则群里 10 个人 10 个意见,谁都不动</li><li><strong>公开沟通要慢一点,内部行动要快一点</strong>——发一条错误对外信息比晚发一小时损失大得多,尤其涉及客户的事件</li></ol><hr><h2 id="十三、踩坑提醒" tabindex="-1">十三、踩坑提醒 <a class="header-anchor" href="#十三、踩坑提醒" aria-label="Permalink to &quot;十三、踩坑提醒&quot;">​</a></h2><ol><li><strong>装了 EDR 就完事了</strong> —— 没人看告警 = 没装</li><li><strong>MTTR 算&quot;开始处置&quot;的时间</strong>,不是&quot;完全恢复&quot;</li><li><strong>告警不分级 = 没有告警</strong> —— P0/P1/P2/P3 必须有清晰定义和 SLA</li><li><strong>遇事第一反应不要 kill -9 / 拔网线</strong> —— 先抓内存,再处置,否则取证全毁</li><li><strong>永远不要 clean,要 rebuild</strong> —— 你不知道还有什么藏着</li><li><strong>日志必须实时外送到独立服务器</strong> —— 存在原机器的日志在攻击者眼里就是待删文件</li><li><strong>没复盘的事件等于没处理</strong> —— 同样手法会打你第二次</li><li><strong>复盘是 blameless 的</strong> —— 找系统漏洞不找人,否则下次没人敢报告</li><li><strong>Splunk 不是答案,流程才是</strong> —— 工具花钱买,流程花时间练,后者更重要</li><li><strong>演习比工具重要</strong> —— 半年一次桌面演习,出事时人才不会慌</li></ol><hr><p><strong>29 的位置</strong>:<strong>前 28 篇是&quot;防被打&quot;,29 是&quot;防被打中的损失扩大&quot;</strong>——两者不冲突,工业界叫<strong>纵深防御</strong>。一流安全团队的标志不是&quot;零事件&quot;,而是「<strong>任何事件都能在小时内发现、几小时内处置、几天内复盘出 action items</strong>」。</p><hr><p>下一篇:<code>30-AI安全.md</code>,这个系列的收官篇——<strong>LLM 把安全攻击面整个翻新了</strong>。讲清楚 Prompt 注入(直接 / 间接 / multi-turn / 跨工具)、模型数据中毒(训练阶段污染)、模型窃取(蒸馏 / 成员推断)、Agent 滥用(过度授权的工具调用)、为什么传统 WAF / DLP / RBAC 在 LLM 面前几乎全失效,以及业内正在做的 prompt firewall / output filter / tool scope / model card 防御链。</p>`,140)])])}const k=a(i,[["render",e]]);export{g as __pageData,k as default};
